        partial void CopyToNextButtonAction(NSObject sender)
        {
            if (!ContextIsValid) return;

            int selected = BaselineGraphView?.SelectedPeak ?? -1;

            if (selected != -1 && BaselineGraphView.IsInjectionZoomed)
            {
                Console.WriteLine("Copying integration length...");
                var length = Data.Injections[selected].IntegrationEndOffset;
                BaselineGraphView.SelectedPeak++;
                Data.Injections[BaselineGraphView.SelectedPeak].SetIntegrationLengthByTime(length);
                BaselineGraphView.FocusPeak();

                _ = Data.Processor.ProcessData();
                UpdateZoomControlHighlighting();
            }
        }

        partial void InjectionViewControlClicked(NSSegmentedControl sender)
        {
            if (!ContextIsValid) return;

            switch (sender.SelectedSegment)
            {
                case 0: BaselineGraphView.SelectedPeak--; break;
                case 2: BaselineGraphView.SelectedPeak++; break;
            }

            UpdateInjectionSelectionUI();
            UpdateZoomControlHighlighting();
        }

        void UpdateInjectionSelectionUI()
        {
            if (!ContextIsValid) return;

            InjectionViewSegControl.SetEnabled(BaselineGraphView.SelectedPeak > 0, 0);
            InjectionViewSegControl.SetEnabled(BaselineGraphView.SelectedPeak < BaselineGraphView.Data.InjectionCount - 1, 2);

            CopyToNextButton.Enabled = BaselineGraphView.SelectedPeak >= 0 && BaselineGraphView.SelectedPeak < BaselineGraphView.Data.InjectionCount - 1;

            if (BaselineGraphView.SelectedPeak != -1)
            {
                // Specific selection, set labels and sliders to corresponding peak
                InjectionViewSegControl.SetLabel("injection #" + (BaselineGraphView.SelectedPeak + 1).ToString(), 1);
                IntegrationLengthControl.FloatValue = Data.Injections[BaselineGraphView.SelectedPeak].IntegrationEndOffset;
                IntegrationLengthLabel.FloatValue = Data.Injections[BaselineGraphView.SelectedPeak].IntegrationEndOffset;
                IntegrationStartDelayLabel.FloatValue = Data.Injections[BaselineGraphView.SelectedPeak].IntegrationStartDelay;
                IntegrationDelayControl.FloatValue = Data.Injections[BaselineGraphView.SelectedPeak].IntegrationStartDelay;
            }
            else
            {
                InjectionViewSegControl.SetLabel("All Selected", 1);
                InjectionViewSegControl.SetEnabled(false, 0);
                InjectionViewSegControl.SetEnabled(false, 2);
            }

            BaselineGraphView.Invalidate();
        }

        partial void ScopeButtonClicked(NSObject sender) => BaselineGraphView.SetFeatureVisibility(ShowBaseline, ShowIntegrationRange, Corrected, ShowCursorInfo);
        partial void DrawFeatureControlClicked(NSSegmentedControl sender) => BaselineGraphView.SetFeatureVisibility(DrawFeatureSegControl);

        partial void CopySettingsToAllClicked(NSObject sender)
        {
            DataManager.CopySelectedProcessToActive();
        }

        void UpdateProcessing(bool replace = true)
        {
            if (!ContextIsValid) return;

            _ = Data.Processor.ProcessData(replace);
        }

        private void OnSelectionChanged(object sender, ExperimentData e)
        {
            if (!ContextIsValid) return;

            var current = DataManager.Current;
            var verticalZoomMode = BaselineGraphView.CurrentVerticalZoomMode;

            BaselineGraphView.Initialize(current);

            BaselineGraphView.SetFeatureVisibility(ShowBaseline, ShowIntegrationRange, Corrected, ShowCursorInfo);
            BaselineGraphView.ApplyVerticalZoomMode(verticalZoomMode);

            UpdateUI();
        }

        private void OnInterpolationCompleted(object sender, EventArgs e)
        {
            if (!ContextIsValid) return;

            if (Processor.BaselineCompleted) BaselineGraphView.Invalidate();

            UpdateUI();
        }
    }
}
